parameters.jsCode:
const response = $json;

return {
  endpoint: 'rankings/daily',
  status: response.status === 'error' ? 'FAILED' : 'OK',
  hasData: Array.isArray(response.data) && response.data.length > 0,
  dataCount: Array.isArray(response.data) ? response.data.length : 0,
  expectedMinimum: 500,
  dataValid: (Array.isArray(response.data) && response.data.length >= 500),
  lastUpdate: response.timestamp || new Date().toISOString(),
  errorMessage: response.error || null
};

const response = $json;
const uptime = response.uptime || 0;
const uptimeHours = Math.floor(uptime / 3600);
const status = response.status || 'unknown';
const healthy = status === 'ok' || status === 'healthy';

return {
  endpoint: 'health',
  status: healthy ? 'OK' : 'DEGRADED',
  healthStatus: status,
  uptime: uptimeHours + 'h',
  timestamp: response.timestamp || new Date().toISOString(),
  checks: response.checks || {},
  databaseConnected: response.database?.connected || false,
  cacheWorking: response.cache?.working || false,
  errorMessage: response.error || null
};

const response = $json;
const hasMetrics = response.profit_factor && response.win_rate && response.total_trades;
const metricsValid = 
  response.profit_factor > 0 && 
  response.win_rate >= 0 && response.win_rate <= 100 &&
  response.total_trades > 0;

return {
  endpoint: 'simulate',
  status: metricsValid ? 'OK' : 'FAILED',
  hasMetrics: hasMetrics,
  metricsValid: metricsValid,
  profitFactor: response.profit_factor || 0,
  winRate: response.win_rate || 0,
  totalTrades: response.total_trades || 0,
  sharpeRatio: response.sharpe_ratio || 0,
  timestamp: new Date().toISOString(),
  errorMessage: response.error || null
};

// Aggregate all health check results
const rankings = $inputWithIndex[0].json;
const health = $inputWithIndex[1].json;
const simulator = $inputWithIndex[2].json;

const allOK = rankings.dataValid && health.status === 'OK' && simulator.status === 'OK';
const failedChecks = [];

if (!rankings.dataValid) failedChecks.push('Rankings API: ' + (rankings.hasData ? 'insufficient data' : 'no data'));
if (health.status !== 'OK') failedChecks.push('Health: ' + health.healthStatus);
if (simulator.status !== 'OK') failedChecks.push('Simulator: invalid metrics');

const severity = allOK ? 'green' : (failedChecks.length === 1 ? 'yellow' : 'red');

return {
  timestamp: new Date().toISOString(),
  overallStatus: allOK ? 'HEALTHY' : 'UNHEALTHY',
  severity: severity,
  passedChecks: 3 - failedChecks.length,
  totalChecks: 3,
  failedChecks: failedChecks,
  failureCount: failedChecks.length,
  details: {
    rankings: rankings,
    health: health,
    simulator: simulator
  }
};

