  metadata: {
    type: 'health_check',
    project: 'pruviq',
    timestamp: $json.timestamp,
    status: $json.overallStatus,
    severity: $json.severity,
    passedChecks: $json.passedChecks,
    totalChecks: $json.totalChecks,
    failedItems: $json.failedChecks,
    evidence: 'Rankings: ' + $json.details.rankings.status + ', Health: ' + $json.details.health.status + ', Simulator: ' + $json.details.simulator.status
  }
};
